CREATE TABLE cwi_sampling_conditions (
	spi_project_id bigint ,
	survey_id bigint ,
	study_area_id bigint ,
	design_component_id bigint ,
	study_area_visit_id bigint ,
	design_component_visit_id bigint ,
	sampling_condition_type varchar(25) ,
	datetime timestamp ,
	air_temperature real,
	wind_speed varchar(25),
	wind_direction varchar(25),
	rainfall_over_24_hours integer,
	rainfall_over_48_hours integer,
	sea_surface_salinity integer,
	sea_surface_temperature real,
	swell_height integer,
	snow_coverage varchar(25),
	snow_depth varchar(25),
	surface_leaf_moisture varchar(25),
	sea_conditions varchar(25),
	turbidity integer,
	cloud_type varchar(25),
	ceiling varchar(25),
	cloud_cover_class varchar(25),
	days_since_5_cm_of_snow varchar(25),
	tide_flow_direction varchar(25),
	official_sunrise varchar(4),
	precipitation_class varchar(25),
	lunar_phase_class varchar(25),
	temperature_variance integer,
	wavelet_height integer,
	preceding_48_hours_air_temp real,
	preceding_48_hours_wind_speed varchar(25),
	preceding_48_hours_precip varchar(25),
	prec48_cloud_cover_class varchar(25),
	water_temperature real,
	ground_moisture varchar(25),
	ground_temperature real,
	note varchar(2000),
	who_created varchar(30) ,
	when_created timestamp ,
	who_updated varchar(30),
	when_updated timestamp
) ;
COMMENT ON TABLE cwi_sampling_conditions IS E'The weather and other environmental conditions at the time a sample istaken.';
COMMENT ON COLUMN cwi_sampling_conditions.air_temperature IS E'Air Temperature is the current air temperature in degrees Celcius.';
COMMENT ON COLUMN cwi_sampling_conditions.ceiling IS E'Code for the height of cloud cover relative to trees and ridges.';
COMMENT ON COLUMN cwi_sampling_conditions.cloud_cover_class IS E'Code for the percentage of cloud cover.';
COMMENT ON COLUMN cwi_sampling_conditions.cloud_type IS E'Code for the cloud type.';
COMMENT ON COLUMN cwi_sampling_conditions.datetime IS E'The sampling conditions date and time.';
COMMENT ON COLUMN cwi_sampling_conditions.days_since_5_cm_of_snow IS E'Code for the number of days since 5 cm of snow fell.';
COMMENT ON COLUMN cwi_sampling_conditions.design_component_id IS E'System generated identifier for the Design-Component.';
COMMENT ON COLUMN cwi_sampling_conditions.design_component_visit_id IS E'System generated identifier for a Design-Component-Visit.';
COMMENT ON COLUMN cwi_sampling_conditions.ground_moisture IS E'Level of moisture present  (DRY, MOIST, WET)';
COMMENT ON COLUMN cwi_sampling_conditions.ground_temperature IS E'Ground temperature, in degrees Centigrade.';
COMMENT ON COLUMN cwi_sampling_conditions.lunar_phase_class IS E'New Moon, 1st Quarter, 2nd Quarter, 3rd Quarter, Full Moon';
COMMENT ON COLUMN cwi_sampling_conditions.note IS E'Additional comments concerning sea conditions.';
COMMENT ON COLUMN cwi_sampling_conditions.official_sunrise IS E'The official sunrise time.';
COMMENT ON COLUMN cwi_sampling_conditions.prec48_cloud_cover_class IS E'The cloud cover class during the previous 48 hours.';
COMMENT ON COLUMN cwi_sampling_conditions.preceding_48_hours_air_temp IS E'Preceding 48 Hours Air Temp is the air temperature during the previous 48 hours, in degrees Celcius.';
COMMENT ON COLUMN cwi_sampling_conditions.preceding_48_hours_precip IS E'Precipitation that occurred during the last 48 hours in mm.';
COMMENT ON COLUMN cwi_sampling_conditions.preceding_48_hours_wind_speed IS E'The wind speed during the previous 48 hours.';
COMMENT ON COLUMN cwi_sampling_conditions.precipitation_class IS E'Drizzle, Foggy, Hard Rain, Light Rain, Misty Drizzle, No Precip';
COMMENT ON COLUMN cwi_sampling_conditions.rainfall_over_24_hours IS E'The amount of rainfall that fell within the last 24 hours (mm)';
COMMENT ON COLUMN cwi_sampling_conditions.rainfall_over_48_hours IS E'The amount of rainl that fell within the last 48 hours (mm)';
COMMENT ON COLUMN cwi_sampling_conditions.sampling_condition_type IS E'The timing of the observation of conditions (START,END)';
COMMENT ON COLUMN cwi_sampling_conditions.sea_conditions IS E'Calm, Light Air, Light Breeze, Gentle Breeze, Moderate Breeze...';
COMMENT ON COLUMN cwi_sampling_conditions.sea_surface_salinity IS E'Sea surface salinity in parts per thousand. (ppt)';
COMMENT ON COLUMN cwi_sampling_conditions.sea_surface_temperature IS E'Sea surface temperature, in degrees Centigrade.';
COMMENT ON COLUMN cwi_sampling_conditions.snow_coverage IS E'0%,1-5%,6-25%,26-50%,51-75%,76-100%';
COMMENT ON COLUMN cwi_sampling_conditions.snow_depth IS E'0 cm, 1-5 cm, 6-25 cm, 26-50 cm, 51-75 cm, 76-100 cm, 101-150 cm,';
COMMENT ON COLUMN cwi_sampling_conditions.spi_project_id IS E'System generated identifier for Project';
COMMENT ON COLUMN cwi_sampling_conditions.study_area_id IS E'System generated identifier for Study-Area.';
COMMENT ON COLUMN cwi_sampling_conditions.study_area_visit_id IS E'System generated identifier for the Study-Area-Visit.';
COMMENT ON COLUMN cwi_sampling_conditions.surface_leaf_moisture IS E'Droplets=Moisture detected, Dry=No Moisture detected';
COMMENT ON COLUMN cwi_sampling_conditions.survey_id IS E'System generated identifier for Survey.';
COMMENT ON COLUMN cwi_sampling_conditions.swell_height IS E'The current swell height, in meters.';
COMMENT ON COLUMN cwi_sampling_conditions.temperature_variance IS E'The temperature variance in +/- degrees Celcius.';
COMMENT ON COLUMN cwi_sampling_conditions.tide_flow_direction IS E'H=Hi, IE=Int. Ebb, IF=Int. Flood, L=Low';
COMMENT ON COLUMN cwi_sampling_conditions.turbidity IS E'The turbidity of the water.';
COMMENT ON COLUMN cwi_sampling_conditions.water_temperature IS E'The water temperature in degrees Celcius.';
COMMENT ON COLUMN cwi_sampling_conditions.wavelet_height IS E'The wavelet height in centimeters.';
COMMENT ON COLUMN cwi_sampling_conditions.wind_direction IS E'The direction the wind is blowing from. N, NNE, NE, E...';
COMMENT ON COLUMN cwi_sampling_conditions.wind_speed IS E'0=Calm, 1=Light Air, 2=Light Breeze, 3=Gentle, 4=Mod 5=Fresh,';
ALTER TABLE cwi_sampling_conditions ADD PRIMARY KEY (spi_project_id,survey_id,study_area_id,design_component_id,study_area_visit_id,design_component_visit_id,sampling_condition_type);
