CREATE TABLE cwi_site_observations (
	spi_project_id bigint ,
	site_id bigint ,
	site_obs_date timestamp,
	site_obs_type varchar(25),
	study_area_id bigint,
	design_component_id bigint,
	wfo_id bigint,
	aspect integer,
	elevation bigint,
	root_restriction_depth integer,
	slope integer,
	surficial_material_1_upper varchar(25),
	site_modifier_soil varchar(25),
	site_modifier_topography varchar(25),
	surface_expression_2_upper varchar(25),
	surface_expression_3_upper varchar(25),
	surficial_material_2_upper varchar(25),
	surficial_material_3_upper varchar(25),
	terrain_texture_1_upper varchar(25),
	terrain_texture_2_upper varchar(25),
	terrain_texture_3_upper varchar(25),
	utm_zone smallint,
	utm_easting integer,
	utm_northing integer,
	latitude double precision,
	longitude double precision,
	map_datum varchar(25),
	gps_ind varchar(1),
	map_sheet varchar(50),
	root_restriction_class varchar(25),
	soil_moisture_regime varchar(25),
	soil_nutrient_regime varchar(25),
	meso_slope_position varchar(25),
	soil_drainage_class varchar(25),
	soil_texture_class varchar(25),
	beu varchar(25),
	bgc_unit varchar(25),
	coarse_fragment_class varchar(25),
	geomorph_1_upper varchar(25),
	geomorph_2_upper varchar(25),
	geomorph_3_upper varchar(25),
	habitat_description varchar(512),
	obs_location varchar(512),
	observer varchar(512),
	humus_form varchar(25),
	ph_method_type varchar(25),
	ecosection varchar(25),
	structural_stage_class varchar(25),
	surface_expression_1_upper varchar(25),
	soil_ph real,
	site_series_code1 varchar(5),
	site_series_code2 varchar(5),
	site_modifier_moisture varchar(25),
	plot_no varchar(25),
	crown_closure integer,
	note varchar(2000),
	who_created varchar(30) ,
	when_created timestamp ,
	who_updated varchar(30),
	when_updated timestamp,
	est_accuracy integer,
	observer_first_name varchar(50),
	observer_last_name varchar(50),
	mailing_address_street varchar(50),
	mailing_address_city varchar(50),
	mailing_address_prov_code varchar(3),
	mailing_address_postal_code varchar(8),
	telephone_number varchar(25),
	email_address varchar(50),
	wsf_source varchar(25),
	condition varchar(1000),
	landscape_context varchar(1000),
	owner varchar(25),
	site_access_description varchar(1000)
) ;
COMMENT ON TABLE cwi_site_observations IS E'An observation of the habitat at a specific location.';
COMMENT ON COLUMN cwi_site_observations.aspect IS E'The orientation of the slope, measured by compass in degrees.';
COMMENT ON COLUMN cwi_site_observations.beu IS E'Broad Ecosystem Unit from Code table.';
COMMENT ON COLUMN cwi_site_observations.bgc_unit IS E'Biogeoclimatic unit including zone, subzone and variant.';
COMMENT ON COLUMN cwi_site_observations.coarse_fragment_class IS E'The percentage of course fragments (>2 mm) by volume in the rooting zone.';
COMMENT ON COLUMN cwi_site_observations.condition IS E'CONDITION is a free-form description of the quality of biotic and abiotic factors within a site.';
COMMENT ON COLUMN cwi_site_observations.crown_closure IS E' Percentage of ground area covered by the vertically projected crown.';
COMMENT ON COLUMN cwi_site_observations.design_component_id IS E'System generated identifier for the Design-Component.';
COMMENT ON COLUMN cwi_site_observations.ecosection IS E'Classification according to BC Ecoregion classification.';
COMMENT ON COLUMN cwi_site_observations.elevation IS E'Elevation of the site in metres.';
COMMENT ON COLUMN cwi_site_observations.email_address IS E'Observer Email Address';
COMMENT ON COLUMN cwi_site_observations.est_accuracy IS E'The estimating accuracy of the UTM, in metres.';
COMMENT ON COLUMN cwi_site_observations.geomorph_1_upper IS E'Geomorphological Process Class #1 Upper';
COMMENT ON COLUMN cwi_site_observations.geomorph_2_upper IS E'Geomorphological Process Class #2 Upper';
COMMENT ON COLUMN cwi_site_observations.geomorph_3_upper IS E'Geomorphological Process Class #3 Upper';
COMMENT ON COLUMN cwi_site_observations.gps_ind IS E'Was a GPS unit used to measure the georeference?';
COMMENT ON COLUMN cwi_site_observations.habitat_description IS E'A general description of the habitat.';
COMMENT ON COLUMN cwi_site_observations.humus_form IS E' The structure of the humus. (e.g. MOR, MODER, MULL)';
COMMENT ON COLUMN cwi_site_observations.landscape_context IS E'LANDSCAPE_CONTEXT is a description of the area and land-uses surrounding the site.';
COMMENT ON COLUMN cwi_site_observations.latitude IS E' Decimal latitude required by GIS users.';
COMMENT ON COLUMN cwi_site_observations.longitude IS E'Decimal longitude converted from UTM value.';
COMMENT ON COLUMN cwi_site_observations.mailing_address_city IS E'Observer Mailing Address City';
COMMENT ON COLUMN cwi_site_observations.mailing_address_postal_code IS E'Observer Mailing Address Postal Code';
COMMENT ON COLUMN cwi_site_observations.mailing_address_prov_code IS E'Observer Mailing Address Province Code';
COMMENT ON COLUMN cwi_site_observations.mailing_address_street IS E'Observer Mailing Address Street';
COMMENT ON COLUMN cwi_site_observations.map_datum IS E'The datum that applies to the georeference (e.g. NAD27, NAD83)';
COMMENT ON COLUMN cwi_site_observations.map_sheet IS E'The map sheet or marine chart that the observed site is on.';
COMMENT ON COLUMN cwi_site_observations.meso_slope_position IS E'The position of the plot relative to the localized catchment area';
COMMENT ON COLUMN cwi_site_observations.note IS E'Additional information about Wildlife Sighting Form or Ground Inspection Form.';
COMMENT ON COLUMN cwi_site_observations.obs_location IS E'Text description of the location.';
COMMENT ON COLUMN cwi_site_observations.observer IS E'Information about the person(s) recording the information.';
COMMENT ON COLUMN cwi_site_observations.observer_first_name IS E'Observer First Name';
COMMENT ON COLUMN cwi_site_observations.observer_last_name IS E'Observer Last Name';
COMMENT ON COLUMN cwi_site_observations.owner IS E'OWNER is a code indicating the type of ownership of the land on which this site occurs.';
COMMENT ON COLUMN cwi_site_observations.ph_method_type IS E' Method used to measure soil pH.';
COMMENT ON COLUMN cwi_site_observations.plot_no IS E'Label to be used for long term monitoring of a site.';
COMMENT ON COLUMN cwi_site_observations.root_restriction_class IS E'The type of restriction that prevents the penetration of roots.';
COMMENT ON COLUMN cwi_site_observations.root_restriction_depth IS E' The depth of the layer that restricts penetration.';
COMMENT ON COLUMN cwi_site_observations.site_access_description IS E'SITE ACCESS DESCRIPTION is free-form text providing directions to the site.';
COMMENT ON COLUMN cwi_site_observations.site_id IS E' System generated unique identifier for Site Observation.';
COMMENT ON COLUMN cwi_site_observations.site_modifier_moisture IS E'Atypical moisture conditions relating to site series. (e.g. x=drier, y=moister)';
COMMENT ON COLUMN cwi_site_observations.site_modifier_soil IS E'Atypical soil conditions relating to site series.';
COMMENT ON COLUMN cwi_site_observations.site_modifier_topography IS E'Atypical soil conditions relating to site series.';
COMMENT ON COLUMN cwi_site_observations.site_obs_date IS E' The date when the site observation was made.';
COMMENT ON COLUMN cwi_site_observations.site_obs_type IS E'Site Obs Type is the type of site described.';
COMMENT ON COLUMN cwi_site_observations.site_series_code1 IS E'Level of biogeoclimatic classification within BEC_UNIT.';
COMMENT ON COLUMN cwi_site_observations.site_series_code2 IS E' A second site series used where site is uniform but transitional';
COMMENT ON COLUMN cwi_site_observations.slope IS E'Slope gradient measured in percent.';
COMMENT ON COLUMN cwi_site_observations.soil_drainage_class IS E'The speed and extent to which water is removed from a mineral soil.';
COMMENT ON COLUMN cwi_site_observations.soil_moisture_regime IS E' The moisture class of the soil used to derive the site series.';
COMMENT ON COLUMN cwi_site_observations.soil_nutrient_regime IS E'Relative to other site series within  the same BCG unit.';
COMMENT ON COLUMN cwi_site_observations.soil_ph IS E'Concentration of hydrogen ions in the mineral soil.';
COMMENT ON COLUMN cwi_site_observations.soil_texture_class IS E'The size distribution of the primary mineral particles.';
COMMENT ON COLUMN cwi_site_observations.spi_project_id IS E'System generated identifier for Project';
COMMENT ON COLUMN cwi_site_observations.structural_stage_class IS E'Stages in the structural development of a forest';
COMMENT ON COLUMN cwi_site_observations.study_area_id IS E'System generated identifier for this study area.';
COMMENT ON COLUMN cwi_site_observations.surface_expression_1_upper IS E'1 letter code indicating small topographic features and landforms';
COMMENT ON COLUMN cwi_site_observations.surface_expression_2_upper IS E'1 letter code indicating small topographic features and landforms';
COMMENT ON COLUMN cwi_site_observations.surface_expression_3_upper IS E'1 letter code indicating small topographic features and landforms';
COMMENT ON COLUMN cwi_site_observations.surficial_material_1_upper IS E'1 letter code indicating relatively young, non-lithified sediment';
COMMENT ON COLUMN cwi_site_observations.surficial_material_2_upper IS E'1 letter code describing relatively young, non-lithified sediment';
COMMENT ON COLUMN cwi_site_observations.surficial_material_3_upper IS E'1 letter code describing relatively young, non-lithified sediment';
COMMENT ON COLUMN cwi_site_observations.telephone_number IS E'Observer Telephone Number';
COMMENT ON COLUMN cwi_site_observations.terrain_texture_1_upper IS E'1 letter code for relative percentage of terrain particles.';
COMMENT ON COLUMN cwi_site_observations.terrain_texture_2_upper IS E'1 letter code for relative percentage of terrain particles.';
COMMENT ON COLUMN cwi_site_observations.terrain_texture_3_upper IS E'1 letter code for relative percentage of terrain particles.';
COMMENT ON COLUMN cwi_site_observations.utm_easting IS E'The longitude measurement of a UTM point.';
COMMENT ON COLUMN cwi_site_observations.utm_northing IS E'The latitude measurement of a UTM point.';
COMMENT ON COLUMN cwi_site_observations.utm_zone IS E'Universal Transverse Mercator zone. Zones 7 to 11 are valid';
COMMENT ON COLUMN cwi_site_observations.wfo_id IS E'System generated unique identifier for Wildlife Feature Observati';
COMMENT ON COLUMN cwi_site_observations.wsf_source IS E'The source of the Wildlife Sighting Record. ie FROGWATCH, WSF-WEB,WSF-FORMS';
