CREATE TABLE cwi_study_areas (
	spi_project_id bigint ,
	study_area_id bigint ,
	study_area_name varchar(100) ,
	no_of_streams_per_grid smallint,
	no_of_reaches_per_stream smallint,
	reach_length real,
	census_unit varchar(25),
	watershed_cd varchar(50),
	utm_zone smallint,
	utm_easting integer,
	utm_northing integer,
	primary_bgc_unit varchar(25),
	secondary_bgc_unit varchar(25),
	primary_ecosection varchar(25),
	secondary_ecosection varchar(25),
	latitude double precision,
	longitude double precision,
	area bigint,
	layout_note varchar(2000),
	study_area_description varchar(2000),
	who_created varchar(30) ,
	when_created timestamp ,
	who_updated varchar(30),
	when_updated timestamp
) ;
COMMENT ON TABLE cwi_study_areas IS E'An area about which population parameters may be inferred based on theresults of the survey.';
COMMENT ON COLUMN cwi_study_areas.area IS E'The area included in the Study Area in square meters.';
COMMENT ON COLUMN cwi_study_areas.census_unit IS E'The code of the census unit for ungulate observations.';
COMMENT ON COLUMN cwi_study_areas.latitude IS E'Decimal latitude converted from the UTM for the Study Area.';
COMMENT ON COLUMN cwi_study_areas.layout_note IS E'The reasons for deviating from the standard grid dimensions.';
COMMENT ON COLUMN cwi_study_areas.longitude IS E'Decimal longitude converted from the UTM for the Study Area.';
COMMENT ON COLUMN cwi_study_areas.no_of_reaches_per_stream IS E'The number of streams represented in each stream sampled.';
COMMENT ON COLUMN cwi_study_areas.no_of_streams_per_grid IS E'The number of streams to be sampled in each grid.';
COMMENT ON COLUMN cwi_study_areas.primary_bgc_unit IS E'The primary Biogeoclimatic Unit which best characterizes the Study Area.';
COMMENT ON COLUMN cwi_study_areas.primary_ecosection IS E'The primary Ecosection which this Study Area represents.';
COMMENT ON COLUMN cwi_study_areas.reach_length IS E'The length of the reach to be sampled, measured in meters.';
COMMENT ON COLUMN cwi_study_areas.secondary_bgc_unit IS E'The secondary Biogeoclimatic Unit which best characterizes the Study Area.';
COMMENT ON COLUMN cwi_study_areas.secondary_ecosection IS E'The secondary Ecosection which this Study Area represents.';
COMMENT ON COLUMN cwi_study_areas.spi_project_id IS E'System generated identifier for Project';
COMMENT ON COLUMN cwi_study_areas.study_area_description IS E'A description of the Study-Area and it"s location.';
COMMENT ON COLUMN cwi_study_areas.study_area_id IS E'System generated identifier for Study-Area.';
COMMENT ON COLUMN cwi_study_areas.study_area_name IS E'A descriptive name of the Study-Area.';
COMMENT ON COLUMN cwi_study_areas.utm_easting IS E' East coordinate in meters for the centre point of the Study-Area.';
COMMENT ON COLUMN cwi_study_areas.utm_northing IS E'North coordinate in meters for the centre point of the Study-Area.';
COMMENT ON COLUMN cwi_study_areas.utm_zone IS E'The two digit zone number for the centre point of the Study-Area.';
COMMENT ON COLUMN cwi_study_areas.watershed_cd IS E'The code for the watershed which best characterizes the Study-Area.';
