CREATE TABLE cwi_wildlife_sightings (
	spi_project_id bigint ,
	site_id bigint ,
	ws_id bigint ,
	taxonomic_unit_id bigint ,
	obs_date timestamp ,
	percent_cover integer,
	vegetation_layer varchar(25),
	no_adult_female integer,
	no_adult_male integer,
	no_adult_unknown integer,
	no_juvenile_male integer,
	no_unknown_unknown integer,
	no_juvenile_female integer,
	no_juvenile_unknown integer,
	no_egg integer,
	activity_cd varchar(25),
	activity_descriptor varchar(25),
	activity_no_cd varchar(25),
	temperature integer,
	wind varchar(25),
	cloud varchar(25),
	precipitation varchar(25),
	note varchar(2000),
	cdc_checked_ind varchar(1) ,
	cdc_element_occurence varchar(25),
	cdc_status varchar(25),
	who_created varchar(30) ,
	when_created timestamp ,
	who_updated varchar(30),
	when_updated timestamp,
	quality_check_result varchar(10),
	secured varchar(1),
	secured_reason varchar(10),
	area_size integer,
	no_plant integer,
	no_egg_mass integer,
	no_larva integer,
	no_pupa integer,
	health_general varchar(25),
	health_specific varchar(25),
	health_cause varchar(25)
) ;
COMMENT ON TABLE cwi_wildlife_sightings IS E'An adhoc observation of wildlife or wildlife sign outside of thestructure of a wildlife inventory';
COMMENT ON COLUMN cwi_wildlife_sightings.activity_cd IS E'The activity of the observed animal.';
COMMENT ON COLUMN cwi_wildlife_sightings.activity_descriptor IS E'One letter code that describes the observation. (e.g. Seen, Heard)';
COMMENT ON COLUMN cwi_wildlife_sightings.activity_no_cd IS E'Number of sign elements (e.g. H= High M=Moderate L=Low T= Trace)';
COMMENT ON COLUMN cwi_wildlife_sightings.area_size IS E'AREA_SIZE is the size of a circumscribed area of occupancy of a species, in square metres. This column is relevant mostly to plants.';
COMMENT ON COLUMN cwi_wildlife_sightings.cdc_checked_ind IS E'Has CDC checked the current record for inclusion in REED.';
COMMENT ON COLUMN cwi_wildlife_sightings.cdc_element_occurence IS E'The Element Occurence in REED that is based on this observation.';
COMMENT ON COLUMN cwi_wildlife_sightings.cdc_status IS E'Status of obs after being reviewed by CDC.';
COMMENT ON COLUMN cwi_wildlife_sightings.cloud IS E'Amount of cloud cover during observations.';
COMMENT ON COLUMN cwi_wildlife_sightings.health_cause IS E'HEALTH_CAUSE is a code indicating the cause of the individual''s health condition.';
COMMENT ON COLUMN cwi_wildlife_sightings.health_general IS E'HEALTH_GENERAL is a code indicating the general health condition of the individual.';
COMMENT ON COLUMN cwi_wildlife_sightings.health_specific IS E'HEALTH_SPECIFIC is a code indicating the specific health condition of the individual.';
COMMENT ON COLUMN cwi_wildlife_sightings.no_adult_female IS E'The number of adult females observed.';
COMMENT ON COLUMN cwi_wildlife_sightings.no_adult_male IS E'The number of adult males observed.';
COMMENT ON COLUMN cwi_wildlife_sightings.no_adult_unknown IS E'The number of adults of unknown sex observed.';
COMMENT ON COLUMN cwi_wildlife_sightings.no_egg IS E'The number of eggs observed.';
COMMENT ON COLUMN cwi_wildlife_sightings.no_egg_mass IS E'NO_EGG_MASS is the number of egg masses observed.';
COMMENT ON COLUMN cwi_wildlife_sightings.no_juvenile_female IS E'The number of juvenile females observed.';
COMMENT ON COLUMN cwi_wildlife_sightings.no_juvenile_male IS E'The number of juvenile males observed.';
COMMENT ON COLUMN cwi_wildlife_sightings.no_juvenile_unknown IS E'The number of juveniles of unknown sex observed.';
COMMENT ON COLUMN cwi_wildlife_sightings.no_larva IS E'NO_LARVA is the number of larvae observed.';
COMMENT ON COLUMN cwi_wildlife_sightings.no_plant IS E'NO_PLANT is the number of plants of a species observed.';
COMMENT ON COLUMN cwi_wildlife_sightings.no_pupa IS E'NO_PUPA is the number of pupae observed.';
COMMENT ON COLUMN cwi_wildlife_sightings.no_unknown_unknown IS E'The number of  unknown age individuals of unknown sex observed.';
COMMENT ON COLUMN cwi_wildlife_sightings.note IS E'Wildlife observation notes.';
COMMENT ON COLUMN cwi_wildlife_sightings.obs_date IS E'The date that a species was observed.';
COMMENT ON COLUMN cwi_wildlife_sightings.percent_cover IS E'GIF: The coverage of a plant species projected onto the ground.';
COMMENT ON COLUMN cwi_wildlife_sightings.precipitation IS E'The type of precipitation that occurred during observations.';
COMMENT ON COLUMN cwi_wildlife_sightings.quality_check_result IS E'The result of the quality check.';
COMMENT ON COLUMN cwi_wildlife_sightings.secured IS E'In indication whether this record should be secured.';
COMMENT ON COLUMN cwi_wildlife_sightings.secured_reason IS E'The reason why this record should be secured.';
COMMENT ON COLUMN cwi_wildlife_sightings.site_id IS E' System generated unique identifier for Site Observation.';
COMMENT ON COLUMN cwi_wildlife_sightings.spi_project_id IS E'System generated identifier for Project';
COMMENT ON COLUMN cwi_wildlife_sightings.taxonomic_unit_id IS E'System generated UID for Taxa.';
COMMENT ON COLUMN cwi_wildlife_sightings.temperature IS E'The temperature in degrees Celcius encountered during observation';
COMMENT ON COLUMN cwi_wildlife_sightings.vegetation_layer IS E'GIF: The vegetation layer that the plant species was found in.';
COMMENT ON COLUMN cwi_wildlife_sightings.wind IS E'The strength of the wind during observations using the Beaufort Scale.';
COMMENT ON COLUMN cwi_wildlife_sightings.ws_id IS E'System generated unique identifier for Wildlife Sighting.';
CREATE INDEX ws_txn_fk_i ON cwi_wildlife_sightings (taxonomic_unit_id);
ALTER TABLE cwi_wildlife_sightings ADD PRIMARY KEY (spi_project_id,site_id,ws_id);

