CREATE TABLE migrate_to_opd_retval (
	retval varchar(2000) ,
	user_name varchar(20) 
) ;
COMMENT ON TABLE migrate_to_opd_retval IS E'Stores, as a temporary reference, the RetVal of the CWI_SPI_OPD.MIGRATEPROJECT function, when the function is called from SPI Import (An MSAccess application used by the Wildlife Species Inventory program)';
COMMENT ON COLUMN migrate_to_opd_retval.retval IS E'The one and only field, for storing the RetVal';
COMMENT ON COLUMN migrate_to_opd_retval.user_name IS E'The user who is running SPI Import and populating this table';
ALTER TABLE migrate_to_opd_retval ADD PRIMARY KEY (retval,user_name);

CREATE TABLE spi_observation_point_xy (
	maps_to_type varchar(1) ,
	maps_to_id integer ,
	utm_zone smallint,
	utm_easting integer,
	utm_northing integer,
	wlo_id bigint,
	tlo_id bigint,
	observation_point_id integer
) ;
COMMENT ON TABLE spi_observation_point_xy IS E'Point coordinates where wildlife observations have been made.  Different observation techniques may have been used, including visual observations and telemetric observations acquired by plane or satellite.';
COMMENT ON COLUMN spi_observation_point_xy.maps_to_id IS E'The primary key ID from the source table.  If "Maps To Type" is "W", this is the WLO_ID and if it''s "T", this is the TLO_ID.';
COMMENT ON COLUMN spi_observation_point_xy.maps_to_type IS E'A code that indicates the source of the point coordinates - "W" for Wildlife Observation or "T" for Telemetry Observation.';
COMMENT ON COLUMN spi_observation_point_xy.observation_point_id IS E'Surrogate primary key for the spatial point.';
COMMENT ON COLUMN spi_observation_point_xy.tlo_id IS E'System generated identifier for Telemetry-Observation.';
COMMENT ON COLUMN spi_observation_point_xy.utm_easting IS E'Universal Trans Mercator (UTM) Easting coordinate';
COMMENT ON COLUMN spi_observation_point_xy.utm_northing IS E'Universal Trans Mercator (UTM) Northing coordinate';
COMMENT ON COLUMN spi_observation_point_xy.utm_zone IS E'Universal Trans Mercator (UTM) Zone coordinate';
COMMENT ON COLUMN spi_observation_point_xy.wlo_id IS E'System generated identifier for Wildlife Observation.';
CREATE INDEX spi_obsrvptx_utm_i ON spi_observation_point_xy (utm_zone, utm_easting, utm_northing, observation_point_id);
ALTER TABLE spi_observation_point_xy ADD PRIMARY KEY (maps_to_type,maps_to_id);

